async function main() {
  // Build a map of language code → language record
  const allLanguages = await prisma.language.findMany();
  if (!allLanguages.length) {
    console.error("❌  No languages found. Add languages in Admin → System → Languages first.");
    process.exit(1);
  }
  const langMap = Object.fromEntries(allLanguages.map(l => [l.code.toLowerCase(), l]));
  console.log(`✅  Found ${allLanguages.length} language(s): ${allLanguages.map(l => `${l.name} (${l.code})`).join(", ")}`);

  const tenants = await prisma.tenant.findMany({ select: { id: true, businessName: true } });
  if (!tenants.length) {
    console.error("❌  No tenants found.");
    process.exit(1);
  }

  let created = 0, updated = 0, skipped = 0;

  for (const tenant of tenants) {
    console.log(`\n📦  Tenant: ${tenant.businessName}`);
    for (const { group, key, languages } of TRANSLATIONS) {
      for (const [rawCode, value] of Object.entries(languages)) {
        const lang = langMap[rawCode.toLowerCase()];
        if (!lang) {
          skipped++;
          continue;
        }
        const existing = await prisma.translation.findFirst({
          where: { tenantId: tenant.id, languageId: lang.id, translationGroup: group, translationKey: key },
        });
        if (existing) {
          await prisma.translation.update({ where: { id: existing.id }, data: { translationValue: value } });
          process.stdout.write("·");
          updated++;
        } else {
          await prisma.translation.create({
            data: { tenantId: tenant.id, languageId: lang.id, translationGroup: group, translationKey: key, translationValue: value },
          });
          process.stdout.write("+");
          created++;
        }
      }
    }
    console.log();
  }

  const uniqueGroups = [...new Set(TRANSLATIONS.map(t => t.group))];
  const langCodesUsed = [...new Set(TRANSLATIONS.flatMap(t => Object.keys(t.languages)))];

  console.log(`\n✅  Done — ${created} created, ${updated} updated${skipped ? `, ${skipped} skipped (language code not found in DB)` : ""}`);
  console.log(`   Languages seeded: ${langCodesUsed.join(", ")}`);
  console.log(`   Groups: ${uniqueGroups.join(", ")}`);
  if (skipped) {
    const missingCodes = [...new Set(
      TRANSLATIONS.flatMap(t => Object.keys(t.languages).filter(c => !langMap[c.toLowerCase()]))
    )];
    console.log(`   ⚠️  Missing language codes in DB: ${missingCodes.join(", ")}`);
  }
}

main()
  .catch(e => { console.error(e); process.exit(1); })
  .finally(() => prisma.$disconnect());
